
.system-bar {
  display: flex;
  align-items: center;
  padding: 7px 14px;
  background: linear-gradient(135deg, var(--c-ink) 0%, #3a3228 100%);
  color: #e5dcc8;
  font-size: var(--font-size-sm);
  gap: 0;
}

.sys-slot {
  display: flex;
  align-items: center;
  gap: 7px;
  flex: 1;
  min-width: 0;
}

.sys-icon {
  font-size: 15px;
  flex-shrink: 0;
  filter: drop-shadow(0 1px 1px rgba(0, 0, 0, 0.3));
}

.sys-body {
  display: flex;
  flex-direction: column;
  min-width: 0;
}

.sys-label {
  font-size: var(--font-size-xs);
  color: #8a8070;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  line-height: 1.2;
}

.sys-value {
  font-size: var(--font-size-md);
  font-weight: 600;
  color: #e5dcc8;
  line-height: 1.3;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.sys-value.is-eternal {
  color: #c8b0e0;
  text-shadow: 0 0 8px rgba(180, 150, 210, 0.4);
}

.sys-divider {
  width: 1px;
  height: 28px;
  background: linear-gradient(
    180deg,
    transparent 0%,
    rgba(255, 255, 255, 0.15) 30%,
    rgba(255, 255, 255, 0.15) 70%,
    transparent 100%
  );
  margin: 0 14px;
  flex-shrink: 0;
}

.sys-time {
  flex: 0 0 auto;
  margin-left: auto;
  padding-left: 12px;
  border-left: 1px solid rgba(255, 255, 255, 0.08);
}

.sys-clock {
  font-family: var(--font-mono);
  font-size: var(--font-size-md);
  color: #8a8070;
  letter-spacing: 0.04em;
}
